INSERT INTO "cards" ("deck_id", "prompt", "answer", "answer_alts", "part_of_speech", "article", "notes", "example_en", "example_de", "frequency_rank", "source") VALUES
  ('b7c8e3a0-6d4f-4e2a-9c1b-000000005000', 'the', 'der', ARRAY[]::text[], 'article', NULL, NULL, 'The man and the woman are cooking; the child is playing.', 'Der Mann und die Frau kochen, das Kind spielt.', 1, 'seed'),
  ('b7c8e3a0-6d4f-4e2a-9c1b-000000005000', 'and', 'und', ARRAY[]::text[], 'conjunction', NULL, NULL, 'The parents and children eat and talk about their day.', 'Die Eltern und Kinder essen und sprechen über ihren Tag.', 2, 'seed'),
  ('b7c8e3a0-6d4f-4e2a-9c1b-000000005000', 'in', 'in', ARRAY[]::text[], 'preposition', NULL, NULL, 'Günter goes into the basement.', 'Günter geht in den Keller.', 3, 'seed'),
  ('b7c8e3a0-6d4f-4e2a-9c1b-000000005000', 'to be', 'sein', ARRAY[]::text[], 'verb', NULL, NULL, 'I’m a teacher, and you’re a police officer, and we’re happy with that.', 'Ich bin Lehrer und du bist Polizist und damit sind wir glücklich.', 4, 'seed'),
  ('b7c8e3a0-6d4f-4e2a-9c1b-000000005000', 'a, an', 'ein', ARRAY[]::text[], 'article', NULL, NULL, 'He’s staying at a hotel.', 'Er wohnt in einem Hotel.', 5, 'seed'),
  ('b7c8e3a0-6d4f-4e2a-9c1b-000000005000', 'to have', 'haben', ARRAY[]::text[], 'verb', NULL, NULL, 'I have a book in my hand.', 'Ich habe ein Buch in der Hand.', 6, 'seed'),
  ('b7c8e3a0-6d4f-4e2a-9c1b-000000005000', 'she, her', 'sie', ARRAY[]::text[], 'pronoun', NULL, NULL, 'Paul visits Anna; she’s Paul’s aunt.', 'Paul besucht Anna, sie ist Pauls Tante.', 7, 'seed'),
  ('b7c8e3a0-6d4f-4e2a-9c1b-000000005000', 'to become, get', 'werden', ARRAY[]::text[], 'verb', NULL, NULL, 'The boy becomes a man.', 'Der Junge wird zum Mann.', 8, 'seed'),
  ('b7c8e3a0-6d4f-4e2a-9c1b-000000005000', 'from, of', 'von', ARRAY[]::text[], 'preposition', NULL, NULL, 'Benjamin is the brother of Anna.', 'Benjamin ist der Bruder von Anna.', 9, 'seed'),
  ('b7c8e3a0-6d4f-4e2a-9c1b-000000005000', 'I', 'ich', ARRAY[]::text[], 'pronoun', NULL, NULL, 'I work and you stay home.', 'Ich arbeite und du bleibst zu Hause.', 10, 'seed'),
  ('b7c8e3a0-6d4f-4e2a-9c1b-000000005000', 'not', 'nicht', ARRAY[]::text[], 'particle', NULL, NULL, 'You can’t smoke in the restaurant.', 'Im Restaurant darf man nicht rauchen.', 11, 'seed'),
  ('b7c8e3a0-6d4f-4e2a-9c1b-000000005000', 'it', 'es', ARRAY[]::text[], 'pronoun', NULL, NULL, 'The child goes to bed; she is tired.', 'Das Kind geht ins Bett, es ist müde.', 12, 'seed'),
  ('b7c8e3a0-6d4f-4e2a-9c1b-000000005000', 'with', 'mit', ARRAY[]::text[], 'preposition', NULL, NULL, 'My brother plays soccer in the garden with Janosch.', 'Mein Bruder spielt mit Janosch Fußball im Garten.', 13, 'seed'),
  ('b7c8e3a0-6d4f-4e2a-9c1b-000000005000', '-self', 'sich', ARRAY[]::text[], 'pronoun', NULL, NULL, 'The child sees itself in the mirror.', 'Das Kind sieht sich im Spiegel.', 14, 'seed'),
  ('b7c8e3a0-6d4f-4e2a-9c1b-000000005000', 'he', 'er', ARRAY[]::text[], 'pronoun', NULL, NULL, 'Jan has good grades in school; he’s a smart child.', 'Jan hat gute Noten in der Schule, er ist ein kluges Kind.', 15, 'seed'),
  ('b7c8e3a0-6d4f-4e2a-9c1b-000000005000', 'on, at, to', 'auf', ARRAY[]::text[], 'preposition', NULL, NULL, 'There’s a glass of water on the table.', 'Auf dem Tisch steht ein Glas Wasser.', 16, 'seed'),
  ('b7c8e3a0-6d4f-4e2a-9c1b-000000005000', 'for', 'für', ARRAY[]::text[], 'preposition', NULL, NULL, 'She’s making coffee for Max.', 'Sie macht einen Kaffee für Max.', 17, 'seed'),
  ('b7c8e3a0-6d4f-4e2a-9c1b-000000005000', 'also, too', 'auch', ARRAY[]::text[], 'adverb', NULL, NULL, 'It’s my birthday too, not just Markus’s.', 'Auch ich habe Geburtstag, nicht nur Markus.', 18, 'seed'),
  ('b7c8e3a0-6d4f-4e2a-9c1b-000000005000', 'at, on', 'an', ARRAY[]::text[], 'preposition', NULL, NULL, 'The picture hangs on the wall.', 'Das Bild hängt an der Wand.', 19, 'seed'),
  ('b7c8e3a0-6d4f-4e2a-9c1b-000000005000', 'that', 'dass', ARRAY[]::text[], 'conjunction', NULL, NULL, 'I suspect the train will be late again.', 'Ich vermute, dass der Zug wieder zu spät kommt.', 20, 'seed'),
  ('b7c8e3a0-6d4f-4e2a-9c1b-000000005000', 'to', 'zu', ARRAY[]::text[], 'particle', NULL, NULL, 'I’m trying to understand you.', 'Ich versuche, dich zu verstehen.', 21, 'seed'),
  ('b7c8e3a0-6d4f-4e2a-9c1b-000000005000', 'as, when', 'als', ARRAY[]::text[], 'conjunction', NULL, NULL, 'When I get home, it’s already dark.', 'Als ich nach Hause komme, ist es schon dunkel.', 22, 'seed'),
  ('b7c8e3a0-6d4f-4e2a-9c1b-000000005000', 'to be able to, can', 'können', ARRAY[]::text[], 'verb', NULL, NULL, 'The children can already ride bicycles.', 'Die Kinder können schon Fahrrad fahren.', 23, 'seed'),
