  ('b7c8e3a0-6d4f-4e2a-9c1b-000000005000', 'how', 'wie', ARRAY[]::text[], 'pronoun', NULL, NULL, 'How long does it take?', 'Wie lange dauert es?', 25, 'seed'),
  ('b7c8e3a0-6d4f-4e2a-9c1b-000000005000', 'we', 'wir', ARRAY[]::text[], 'pronoun', NULL, NULL, 'Fernando and I are going on vacation; we’re going in summer.', 'Fernando und ich wollen Urlaub machen, wir fahren im Sommer.', 26, 'seed'),
  ('b7c8e3a0-6d4f-4e2a-9c1b-000000005000', 'you, her', 'ihr', ARRAY[]::text[], 'pronoun', NULL, NULL, 'The girl annoys her brother.', 'Das Mädchen ärgert ihren Bruder.', 27, 'seed'),
  ('b7c8e3a0-6d4f-4e2a-9c1b-000000005000', 'so, thus, the way, such', 'so', ARRAY[]::text[], 'adverb', NULL, NULL, 'I watch Klaus and do everything the way he does.', 'Ich beobachte Klaus und mache alles so wie er.', 28, 'seed'),
