  ('b7c8e3a0-6d4f-4e2a-9c1b-000000005000', 'his, its', 'sein', ARRAY[]::text[], 'pronoun', NULL, NULL, 'The boy annoys his sister.', 'Der Junge ärgert seine Schwester.', 30, 'seed'),
  ('b7c8e3a0-6d4f-4e2a-9c1b-000000005000', 'but', 'aber', ARRAY[]::text[], 'conjunction', NULL, NULL, 'The sun is shining, but it’s still cold.', 'Die Sonne scheint, aber es ist trotzdem kalt.', 31, 'seed'),
  ('b7c8e3a0-6d4f-4e2a-9c1b-000000005000', 'one, you, they', 'man', ARRAY[]::text[], 'pronoun', NULL, NULL, 'They tell stories here.', 'Hier erzählt man sich Geschichten.', 32, 'seed'),
  ('b7c8e3a0-6d4f-4e2a-9c1b-000000005000', 'still, yet', 'noch', ARRAY[]::text[], 'adverb', NULL, NULL, 'Do you still have any questions?', 'Habt ihr sonst noch Fragen?', 33, 'seed'),
  ('b7c8e3a0-6d4f-4e2a-9c1b-000000005000', 'after, toward', 'nach', ARRAY[]::text[], 'preposition', NULL, NULL, 'After lunch we go for a walk.', 'Nach dem Mittagessen gehen wir spazieren.', 34, 'seed'),
  ('b7c8e3a0-6d4f-4e2a-9c1b-000000005000', 'or', 'oder', ARRAY[]::text[], 'conjunction', NULL, NULL, 'Are you coming by bike or are you going by bus?', 'Kommst du mit dem Fahrrad oder fährst du mit dem Bus?', 35, 'seed'),
  ('b7c8e3a0-6d4f-4e2a-9c1b-000000005000', 'all', 'all', ARRAY[]::text[], 'pronoun', NULL, NULL, 'We are all looking forward to our vacation.', 'Wir freuen uns alle auf den Urlaub.', 36, 'seed'),
  ('b7c8e3a0-6d4f-4e2a-9c1b-000000005000', 'out, out of, from', 'aus', ARRAY[]::text[], 'preposition', NULL, NULL, 'Thomas looks out the window.', 'Thomas schaut aus dem Fenster.', 37, 'seed'),
  ('b7c8e3a0-6d4f-4e2a-9c1b-000000005000', 'what', 'was', ARRAY[]::text[], 'pronoun', NULL, NULL, 'What do you say?', 'Was sagst du?', 38, 'seed'),
  ('b7c8e3a0-6d4f-4e2a-9c1b-000000005000', 'only', 'nur', ARRAY[]::text[], 'adverb', NULL, NULL, 'It only costs two euros.', 'Das kostet nur zwei Euro.', 39, 'seed'),
