  ('b7c8e3a0-6d4f-4e2a-9c1b-000000005000', 'then', 'dann', ARRAY[]::text[], 'adverb', NULL, NULL, 'First we go shopping, then we go to a restaurant.', 'Erst gehen wir einkaufen und dann in ein Restaurant.', 41, 'seed'),
  ('b7c8e3a0-6d4f-4e2a-9c1b-000000005000', 'if, when', 'wenn', ARRAY[]::text[], 'conjunction', NULL, NULL, 'I’ll tell you when we see each other.', 'Ich erzähle es dir, wenn wir uns sehen.', 42, 'seed'),
