  ('b7c8e3a0-6d4f-4e2a-9c1b-000000005000', 'other', 'andere (r', ARRAY[]::text[], 'pronoun', NULL, NULL, 'There’s another way to the station.', 'Es gibt noch einen anderen Weg zum Bahnhof.', 59, 'seed'),
