  ('b7c8e3a0-6d4f-4e2a-9c1b-000000005000', 'every', 'jede (r', ARRAY[]::text[], 'pronoun', NULL, NULL, 'We go on vacation every summer.', 'Wir fahren jeden Sommer in den Urlaub.', 87, 'seed'),
