  ('b7c8e3a0-6d4f-4e2a-9c1b-000000005000', 'under', 'unter', ARRAY[]::text[], 'preposition', NULL, NULL, 'Under the bridge a river flows.', 'Unter der Brücke fließt ein Fluss.', 89, 'seed'),
