-- Replace the global frequency word corpus with a higher-quality deck. Generated
-- from an Anki deck by scripts/gen-words.ts; cleaning rules in server/db/words-parse.ts.
-- The original corpus (seeded by the frozen 0005, sentences split by 0008) had weak
-- example sentences. This swaps in ~5007 words with natural sentences, reusing the
-- SAME global deck row (id below). It DELETES the old corpus cards first, cascading
-- their review_state/reviews — progress on the old corpus is intentionally discarded.
-- Applied to dev via db:migrate and to prod by the CI migrate job on push to main.

-- Ensure the global deck row exists (a fresh DB may not have run 0005), then refresh it.
SELECT 'b7c8e3a0-6d4f-4e2a-9c1b-000000005000'::uuid, NULL, 'German — Frequency 5000', 'seed', 'The ~5,000 most frequent German words, ordered by frequency, each with an example sentence.'
WHERE NOT EXISTS (SELECT 1 FROM "decks" WHERE "id" = 'b7c8e3a0-6d4f-4e2a-9c1b-000000005000'::uuid);
UPDATE "decks" SET "name" = 'German — Frequency 5000', "description" = 'The ~5,000 most frequent German words, ordered by frequency, each with an example sentence.'
WHERE "id" = 'b7c8e3a0-6d4f-4e2a-9c1b-000000005000'::uuid;

-- Drop the old corpus cards (cascades review_state + reviews via ON DELETE CASCADE).
DELETE FROM "cards" WHERE "deck_id" = 'b7c8e3a0-6d4f-4e2a-9c1b-000000005000'::uuid;

